import { resolve } from 'node:path';
import { writeFileSync } from 'node:fs';

/** Generate _entry.ts — uses Runner to boot the entity tree. */
export function generateEntry(generatedDir: string, root: string | undefined, dev: boolean) {
  const entryLines = [
    '// AUTO-GENERATED by interactkit build — do not edit',
    "import 'dotenv/config';",
    "import 'reflect-metadata';",
    dev
      ? "import { Runner, InProcessBusAdapter, DevLogAdapter } from '@interactkit/sdk';"
      : "import { Runner, InProcessBusAdapter } from '@interactkit/sdk';",
    "import { entityTree } from './entity-tree.js';",
  ];

  if (root) {
    const colonIdx = root.lastIndexOf(':');
    if (colonIdx === -1) {
      console.error('--root must be in the format path/to/file:ExportName (e.g. src/entities/agent:Agent)');
      process.exit(1);
    }
    const rootFile = root.slice(0, colonIdx);
    const rootExport = root.slice(colonIdx + 1);
    const importPath = `./${rootFile.replace(/^src\//, '')}.js`;

    entryLines.push(
      `import { ${rootExport} } from '${importPath}';`,
      '',
      'const runner = new Runner(entityTree, {',
      '  pubsubs: [{ name: "InProcessBusAdapter", adapter: new InProcessBusAdapter() }],',
      '  databases: [],',
      dev ? '  loggers: [{ name: "DevLogAdapter", adapter: new DevLogAdapter() }],' : '  loggers: [],',
      '});',
      '',
      `const { root, shutdown } = await runner.boot(${rootExport} as any);`,
      "console.log(`▸ booted entity tree from ${root.id}`);",
      '',
      '// Graceful shutdown',
      "process.on('SIGINT', async () => {",
      '  await shutdown();',
      '  process.exit(0);',
      '});',
    );
  } else {
    entryLines.push("export * from './index.js';");
  }

  entryLines.push('');
  writeFileSync(resolve(generatedDir, '_entry.ts'), entryLines.join('\n'), 'utf-8');
}
